#include<bits/stdc++.h>
using namespace std;
struct Node{
  int x,t;  
};
bool cmp(Node x,Node y){
    if(x.x!=y.x) return x.x<y.x;
    else return x.t<y.t;
}
Node a[100005];
int f[100005];
int n;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i].x>>a[i].t;
    }
    sort(a+1,a+n+1,cmp);
    memset(f,0,sizeof(f));
    f[0]=0;
    int ans=-1e9;
    for(int i=1;i<=n;i++){
       /* for(int j=0;j<i;j++){
            if(a[i].t-a[j].t>=a[i].x-a[j].x){
                f[i]=max(f[i],f[j]+1);
            }
        }*/
        if(a[i].x>a[i].t) continue;
        int l=0,r=i-1,b=0;
        while(l<=r){
            int mid=(l+r)>>1;
            if(a[i].x>a[mid].x&&a[i].t-a[mid].t>=a[i].x-a[mid].x){
                b=mid;
                l=mid+1;
            }
            else{
                r=mid-1;
            }
        }
        //cout<<ans<<endl;
        f[i]=f[b]+1;
       // cout<<f[i]<<endl;
        ans=max(ans,f[i]);
    }
    cout<<ans;
}
